const d = $input.first().json;

const workflowName = (d.workflow && d.workflow.name) || 'Unknown workflow';
const nodeName = (d.node && d.node.name) || d.lastNodeExecuted || 'Unknown node';
const message = (d.error && d.error.message) || d.errorMessage || JSON.stringify(d).slice(0, 500);
const executionUrl = (d.execution && d.execution.url) || '';

return [{ json: { workflowName, nodeName, message, executionUrl } }];
